import { describe, it, expect } from 'vitest';
import { truncateContent } from './truncateContent';

describe('truncateContent', () => {
  it('should handle happy path with content shorter than maxLength', () => {
    const content = 'Hello, World!';
    const result = truncateContent(content, 20);
    expect(result).toBe(content);
  });

  it('should handle edge case with content exactly maxLength', () => {
    const content = 'a'.repeat(80);
    const result = truncateContent(content);
    expect(result).toBe(content);
  });

  it('should handle null/empty/0 inputs', () => {
    expect(truncateContent(undefined as unknown as string)).toBe('');
    expect(truncateContent(null as unknown as string)).toBe('');
    expect(truncateContent('', 50)).toBe('');
    expect(truncateContent('Test', 0)).toBe('');
  });
});

